import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type GitLogData = {
  branch: string
  commits: CommitEntry[]
}

const parseGitLog = (raw: string): CommitEntry[] =>
  raw
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => {
      const [sha, author, date, ...messageParts] = line.split('|')
      return {
        sha: sha.trim(),
        author: author.trim(),
        date: date.trim(),
        message: messageParts.join('|').trim(),
      }
    })

export const gitCommitSensor: SensorFactory = {
  name: 'git-commit-sensor',
  snapshotPath: 'git-commits.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    // Fetch latest from remote
    const fetchProc = Bun.spawn(['git', 'fetch', 'origin', 'main', '--quiet'], {
      stdout: 'ignore',
      stderr: 'ignore',
    })
    await fetchProc.exited

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    // Read last 50 commits on origin/main
    const logProc = Bun.spawn(
      ['git', 'log', 'origin/main', '--format=%H|%an|%aI|%s', '-n', '50'],
      { stdout: 'pipe', stderr: 'ignore' },
    )
    const raw = await new Response(logProc.stdout).text()
    await logProc.exited

    const commits = parseGitLog(raw)
    return { branch: 'main', commits } satisfies GitLogData
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as GitLogData

    // First run — report all current commits as initial state
    if (!previous) {
      return curr.commits.length > 0 ? { newCommits: curr.commits } : null
    }

    const prev = previous.data as GitLogData
    const knownShas = new Set(prev.commits.map((c) => c.sha))
    const newCommits = curr.commits.filter((c) => !knownShas.has(c.sha))

    return newCommits.length > 0 ? { newCommits } : null
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type CommitDelta = {
  newCommits: CommitEntry[]
}

let wsConnection: WebSocket | null = null

const getWebSocket = (): WebSocket | null => {
  const url = process.env.WS_ALERT_URL
  if (!url) return null

  if (wsConnection && wsConnection.readyState === WebSocket.OPEN) {
    return wsConnection
  }

  wsConnection = new WebSocket(url)
  wsConnection.addEventListener('error', () => {
    wsConnection = null
  })
  wsConnection.addEventListener('close', () => {
    wsConnection = null
  })

  return wsConnection
}

const notificationHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return

    const ws = getWebSocket()
    if (!ws || ws.readyState !== WebSocket.OPEN) return

    ws.send(
      JSON.stringify({
        type: 'git-commit-alert',
        timestamp: new Date().toISOString(),
        content: msg.content,
      }),
    )
  },
}

export const gitCommitGoal = createGoal((_trigger) => ({
  threads: {
    'git-commit-watch': bThread(
      [
        // Step 1: Wait for a delta from the git commit sensor
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            (detail as SensorDeltaDetail).sensor === 'git-commit-sensor',
        }),
        // Step 2: Request a task so the agent formats and sends the alert
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'New commits were pushed to main.',
                'Read the sensor delta to get commit details (SHAs, authors, messages).',
                'Format a concise summary and emit a proactive message with the commit details',
                'so the notification handler can relay it over WebSocket.',
              ].join(' '),
            },
          },
        }),
      ],
      true, // repeat — continuously watch for new pushes
    ),
  },
  handlers: notificationHandler,
}))

