type HealthDelta = {
  previousStatus: number | null
  currentStatus: number
  ok: boolean
  timestamp: string
}

const isNon200HealthDelta = ({ type, detail }: { type: string; detail: unknown }): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const sensorDetail = detail as SensorDeltaDetail
  if (sensorDetail.sensor !== 'http-health') return false
  const delta = sensorDetail.delta as HealthDelta
  return !delta.ok
}

const notificationHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return
    const webhookUrl = process.env.DISCORD_WEBHOOK_URL
    if (!webhookUrl) return
    fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: msg.content }),
    }).catch(() => {/* non-fatal */})
  },
}

export const healthAlertGoal = createGoal((_trigger) => ({
  threads: {
    'health-alert': bThread(
      [
        bSync({
          waitFor: isNon200HealthDelta,
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'The HTTP health check at https://api.example.com/health returned a non-200 status. ' +
                'Compose an alert message with the status code and timestamp, then send it to the Discord notification channel.',
            },
          },
        }),
      ],
      true,
    ),
  },
  handlers: notificationHandler,
}))

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type AccumulatedDelta = {
  sensor: string
  delta: unknown
  timestamp: string
}

const formatDigestEmail = (deltas: AccumulatedDelta[]): string => {
  const date = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })

  const grouped = deltas.reduce<Record<string, AccumulatedDelta[]>>((acc, entry) => {
    acc[entry.sensor] ??= []
    acc[entry.sensor].push(entry)
    return acc
  }, {})

  const sections = Object.entries(grouped)
    .map(([sensor, entries]) => {
      const bullets = entries
        .map((e) => `  - [${e.timestamp}] ${JSON.stringify(e.delta)}`)
        .join('\n')
      return `=== ${sensor} ===\n${bullets}`
    })
    .join('\n\n')

  return [
    `Daily Sensor Digest — ${date}`,
    '',
    `${deltas.length} change(s) detected in the last 24 hours.`,
    '',
    sections,
  ].join('\n')
}

const sendDigestEmail = async (body: string): Promise<void> => {
  const relayUrl = process.env.SMTP_RELAY_URL
  const from = process.env.DIGEST_EMAIL_FROM ?? 'agent@example.com'
  const to = process.env.DIGEST_EMAIL_TO ?? 'team@example.com'

  if (!relayUrl) {
    console.error('[email-digest] SMTP_RELAY_URL not set, skipping send')
    return
  }

  const res = await fetch(relayUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      from,
      to,
      subject: `Daily Sensor Digest — ${new Date().toISOString().slice(0, 10)}`,
      text: body,
    }),
  })

  if (!res.ok) {
    console.error(`[email-digest] SMTP relay returned ${res.status}`)
  }
}

export const emailDigestGoal = createGoal((_trigger) => {
  const accumulated: AccumulatedDelta[] = []

  const handlers: DefaultHandlers = {
    [AGENT_EVENTS.sensor_delta]: ({ detail }) => {
      const delta = detail as SensorDeltaDetail
      accumulated.push({
        sensor: delta.sensor,
        delta,
        timestamp: new Date().toISOString(),
      })
    },

    [AGENT_EVENTS.message]: ({ detail }) => {
      const msg = detail as { source?: string; content?: string }
      if (msg.source !== 'proactive') return
      if (accumulated.length === 0) return

      const body = formatDigestEmail(accumulated)
      sendDigestEmail(body)
        .then(() => {
          accumulated.length = 0
        })
        .catch(() => {
          console.error('[email-digest] Send failed, will retry next cycle')
        })
    },
  }

  return {
    threads: {
      'daily-email-digest': bThread(
        [
          // Step 1: Wait for at least one sensor delta to arrive
          bSync({
            waitFor: ({ type }) => type === AGENT_EVENTS.sensor_delta,
          }),
          // Step 2: Hold until the 8am tick — deltas keep accumulating via handler
          bSync({
            waitFor: ({ type }) =>
              type === AGENT_EVENTS.tick &&
              new Date().getHours() === 8,
          }),
          // Step 3: Request the agent to compose and dispatch the digest
          bSync({
            request: {
              type: AGENT_EVENTS.task,
              detail: {
                prompt:
                  'Compose and send the daily sensor digest email. ' +
                  'Summarize all accumulated sensor changes from the last 24 hours, ' +
                  'grouped by sensor name, and dispatch via the notification handler.',
              },
            },
          }),
        ],
        true, // repeat: restart after each digest cycle
      ),
    },
    handlers,
  }
})

import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type BackendStatus = {
  backend: 'local-gpu' | 'cloud-api'
  endpoint: string
  respondedMs: number
}

type BackendDelta = {
  backend: 'local-gpu' | 'cloud-api'
  changedFrom: 'local-gpu' | 'cloud-api' | null
}

const LOCAL_GPU_ENDPOINT = process.env.LOCAL_GPU_ENDPOINT ?? 'http://localhost:8080/health'
const CLOUD_API_ENDPOINT = process.env.CLOUD_API_ENDPOINT ?? 'https://api.inference.cloud/v1'
const PROBE_TIMEOUT_MS = 4_000

export const inferenceBackendSensor: SensorFactory = {
  name: 'inference-backend',
  snapshotPath: 'inference-backend.json',

  async read(signal: AbortSignal): Promise<BackendStatus> {
    const start = performance.now()

    try {
      const controller = new AbortController()
      const onAbort = () => controller.abort()
      signal.addEventListener('abort', onAbort, { once: true })

      const timeout = setTimeout(() => controller.abort(), PROBE_TIMEOUT_MS)
      const response = await fetch(LOCAL_GPU_ENDPOINT, {
        method: 'GET',
        signal: controller.signal,
      })
      clearTimeout(timeout)
      signal.removeEventListener('abort', onAbort)

      if (response.ok) {
        return {
          backend: 'local-gpu',
          endpoint: LOCAL_GPU_ENDPOINT,
          respondedMs: Math.round(performance.now() - start),
        }
      }
    } catch {
      // Local GPU unreachable — fall through to cloud
    }

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    return {
      backend: 'cloud-api',
      endpoint: CLOUD_API_ENDPOINT,
      respondedMs: Math.round(performance.now() - start),
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): BackendDelta | null {
    const curr = current as BackendStatus

    if (!previous) {
      return { backend: curr.backend, changedFrom: null }
    }

    const prev = previous.data as BackendStatus

    if (curr.backend !== prev.backend) {
      return { backend: curr.backend, changedFrom: prev.backend }
    }

    return null
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'

type BackendDelta = {
  backend: 'local-gpu' | 'cloud-api'
  changedFrom: 'local-gpu' | 'cloud-api' | null
}

const HEARTBEAT_LOCAL_GPU = 300_000 // 5 minutes — aggressive, free inference
const HEARTBEAT_CLOUD_API = 7_200_000 // 2 hours — conservative, metered API

/** Event type for the agent loop's heartbeat control surface */
const SET_HEARTBEAT = 'set_heartbeat'

const isBackendDelta = (type: string, detail: unknown, target: BackendDelta['backend']): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const d = detail as SensorDeltaDetail
  if (d.sensor !== 'inference-backend') return false
  const delta = d.delta as BackendDelta
  return delta.backend === target
}

export const costAwareHeartbeatGoal = createGoal((_trigger) => ({
  threads: {
    /**
     * When local GPU comes online, switch to aggressive 5-min heartbeat.
     * Local inference is free so frequent polling costs nothing.
     */
    'heartbeat-on-local-gpu': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) => isBackendDelta(type, detail, 'local-gpu'),
        }),
        bSync({
          request: {
            type: SET_HEARTBEAT,
            detail: { intervalMs: HEARTBEAT_LOCAL_GPU },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'Local GPU detected — heartbeat set to 5 minutes. ' +
                'Log the backend transition and confirm all sensors are operating at the aggressive interval.',
            },
          },
        }),
      ],
      true,
    ),

    /**
     * When falling back to cloud API, switch to conservative 2-hour heartbeat.
     * Cloud inference is metered so we minimize polling to control costs.
     */
    'heartbeat-on-cloud-api': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) => isBackendDelta(type, detail, 'cloud-api'),
        }),
        bSync({
          request: {
            type: SET_HEARTBEAT,
            detail: { intervalMs: HEARTBEAT_CLOUD_API },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'Cloud API fallback detected — heartbeat set to 2 hours. ' +
                'Log the backend transition and summarize pending sensor work that will now run at reduced frequency.',
            },
          },
        }),
      ],
      true,
    ),
  },
}))
